
class Handler {final ExecAction? exec; final HTTPGetAction? httpGet; final TCPSocketAction? tcpSocket; Handler({this.exec, this.httpGet, this.tcpSocket}); factory Handler.fromJson(Map<String, dynamic> json) {return Handler(exec: json['exec'] != null ? ExecAction.fromJson(json['exec']) : null, httpGet: json['httpGet'] != null ? HTTPGetAction.fromJson(json['httpGet']) : null, tcpSocket: json['tcpSocket'] != null ? TCPSocketAction.fromJson(json['tcpSocket']) : null);} Map<String, dynamic> toJson() {return {if (exec != null) 'exec' : exec!.toJson(), if (httpGet != null) 'httpGet' : httpGet!.toJson(), if (tcpSocket != null) 'tcpSocket' : tcpSocket!.toJson()};}}
